/**
 * Reauthentication finish request that completes the WebAuthn ceremony and binds to the operation kind.
 */
export interface ReauthenticationFinishRequest {
  requestId: UlidId;
  kind: ReauthenticationSessionKind;
  credential: WebAuthnAssertionCredential;
}

/**
 * Reauthentication session kind bound to a high-risk operation.
 */
export type ReauthenticationSessionKind =
  (typeof ReauthenticationSessionKind)[keyof typeof ReauthenticationSessionKind];

// eslint-disable-next-line @typescript-eslint/no-redeclare
export const ReauthenticationSessionKind = {
  'device-link': 'device-link',
  'passkey-delete': 'passkey-delete',
} as const;

/**
 * Reauthentication session response issued after a fresh WebAuthn reauthentication.
 */
export interface ReauthenticationSessionResponse {
  requestId: UlidId;
  reauthSessionId: UlidId;
  kind: ReauthenticationSessionKind;
  expiresAt: string;
}

/**
 * Reauthentication start request that binds the ceremony to a high-risk operation kind.
 */
export interface ReauthenticationStartRequest {
  kind: ReauthenticationSessionKind;
}

export interface RecoveryAcceptedResponse {
  requestId: UlidId;
  accepted: boolean;
}

export interface RecoveryConsumeRequest {
  token: string;
}

export interface RecoveryConsumeResponse {
  requestId: UlidId;
  recoveryTokenId: UlidId;
  recoverySessionId: UlidId;
  /** Alias of recoverySessionId for client convenience. */
  recovery_session: UlidId;
  expiresAt: string;
  kind: TokenKind;
}

/**
 * Finish passkey registration ceremony using a recovery session.
 */
export interface RecoveryPasskeyFinishRequest {
  recovery_session: UlidId;
  /** session credential の発行方式。browser は cookie、external client は bearer を指定する。 */
  credentialMode: CredentialMode;
  credential: WebAuthnAttestationCredential;
}

/**
 * Start passkey registration ceremony using a recovery session.
 */
export interface RecoveryPasskeyStartRequest {
  recovery_session: UlidId;
}

export interface RecoveryRequest {
  email: string;
}

/**
 * Product context refresh の credential mode 別 success response。Cookie mode は Cookie command を表現でき、Bearer mode は refreshToken body を返す。
 */
export type RefreshTokenResponse =
  | ProductCookieContextRefreshResponse
  | ProductBearerContextRefreshResponse;

/**
 * ログイン中のセッション（デバイス）を表すアイテム。各セッションは一意の sessionId を持つ。
 */
export interface SessionItem {
  sessionId: UlidId;
  deviceName: string;
  loginAt: string;
  lastActiveAt: string;
  ipHash: string;
  isCurrentSession: boolean;
}

/**
 * ログイン中のセッション一覧レスポンス。認証済みアカウントが所有する全セッションを含む。
 */
export interface SessionListResponse {
  requestId: UlidId;
  sessions: SessionItem[];
}

export interface StatusResponse {
  message: string;
  timestamp: string;
}

/**
 * パスキー追加トークンの発行種別。recovery は紛失時復旧、device-link は認証済み端末からの新端末追加。
 */
export type TokenKind = (typeof TokenKind)[keyof typeof TokenKind];

// eslint-disable-next-line @typescript-eslint/no-redeclare
export const TokenKind = {
  recovery: 'recovery',
  'device-link': 'device-link',
} as const;

/**
 * Canonical ULID string used for auth-owned resource and correlation identifiers.
 */
export type UlidId = string;

/**
 * 現在の Product Account の AccountSetting.locale を更新するリクエスト。Account ID は bearer session から確定するため body には含めない。
 */
export interface UpdateAccountSettingRequest {
  /** 保存したい Product AccountSetting.locale。対応値以外は API 実装で拒否し、永続値を変更しない。 */
  locale: AccountLocale;
}

/**
 * WebAuthn PublicKeyCredential for login (navigator.credentials.get result).
 */
export interface WebAuthnAssertionCredential {
  id: string;
  rawId: string;
  type: string;
  response: WebAuthnAssertionResponse;
  authenticatorAttachment?: string;
}

/**
 * WebAuthn AuthenticatorAssertionResponse (login).
 */
export interface WebAuthnAssertionResponse {
  /** base64url-encoded clientDataJSON. */
  clientDataJSON: string;
  /** base64url-encoded authenticatorData. */
  authenticatorData: string;
  /** base64url-encoded signature. */
  signature: string;
  /** base64url-encoded userHandle (optional). */
  userHandle?: string;
}

/**
 * WebAuthn PublicKeyCredential for registration (navigator.credentials.create result).
 */
export interface WebAuthnAttestationCredential {
  id: string;
  rawId: string;
  type: string;
  response: WebAuthnAttestationResponse;
  authenticatorAttachment?: string;
}

/**
 * WebAuthn AuthenticatorAttestationResponse (registration).
 */
export interface WebAuthnAttestationResponse {
  /** base64url-encoded clientDataJSON. */
  clientDataJSON: string;
  /** base64url-encoded attestationObject. */
  attestationObject: string;
  transports?: string[];
}

/**
 * WebAuthn AuthenticatorResponse inner object.
 */
export interface WebAuthnAuthenticatorResponse {
  /** base64url-encoded clientDataJSON. */
  clientDataJSON: string;
}

/**
 * Credential descriptor used in allowCredentials and excludeCredentials lists.
 */
export interface WebAuthnCredentialDescriptor {
  type: string;
  /** base64url-encoded credential ID. */
  id: string;
  transports?: string[];
}

/**
 * WebAuthn public key credential parameter (algorithm descriptor).
 */
export interface WebAuthnCredentialParameter {
  type: string;
  /** COSE algorithm identifier. */
  alg: number;
}

/**
 * WebAuthn user entity (id is base64url-encoded bytes).
 */
export interface WebAuthnUserEntity {
  /** base64url-encoded user ID bytes. */
  id: string;
  name: string;
  displayName: string;
}

